// src/components/PersonalityQuiz.js
import React, { useState } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip } from 'recharts';
import './PersonalityQuiz.css';

const questions = [
  { id: 1, text: " .", reverse: true, domain: "extraversion" },
  { id: 2, text: "     .", domain: "agreeableness" },
  { id: 3, text: "   .", reverse: true, domain: "conscientiousness" },
  { id: 4, text: " .", domain: "negativeEmotionality" },
  { id: 5, text: ", ,   .", domain: "openMindedness" },
  { id: 6, text: "  .", domain: "extraversion" },
  { id: 7, text: "     .", reverse: true, domain: "agreeableness" },
  { id: 8, text: "   .", reverse: true, domain: "conscientiousness" },
  { id: 9, text: "  .", domain: "negativeEmotionality" },
  { id: 10, text: "    .", reverse: true, domain: "openMindedness" },
  { id: 11, text: " .", domain: "extraversion" },
  { id: 12, text: "     .", domain: "agreeableness" },
  { id: 13, text: "       .", domain: "conscientiousness" },
  { id: 14, text: "    .", reverse: true, domain: "negativeEmotionality" },
  { id: 15, text: "    .", domain: "openMindedness" },
  { id: 16, text: " .", domain: "extraversion" },
  { id: 17, text: "  .", reverse: true, domain: "agreeableness" },
  { id: 18, text: "   .", domain: "conscientiousness" },
  { id: 19, text: "   .", reverse: true, domain: "negativeEmotionality" },
  { id: 20, text: "   .", reverse: true, domain: "openMindedness" },
  { id: 21, text: "    .", reverse: true, domain: "extraversion" },
  { id: 22, text: "     .", domain: "agreeableness" },
  { id: 23, text: "   .", domain: "conscientiousness" },
  { id: 24, text: "     .", reverse: true, domain: "negativeEmotionality" },
  { id: 25, text: "     .", domain: "openMindedness" },
  { id: 26, text: "   .", reverse: true, domain: "extraversion" },
  { id: 27, text: "     .", reverse: true, domain: "agreeableness" },
  { id: 28, text: "    .", reverse: true, domain: "conscientiousness" },
  { id: 29, text: "    .", domain: "negativeEmotionality" },
  { id: 30, text: " .", reverse: true, domain: "openMindedness" }
];

const domainDescriptions = {
  extraversion: "      .",
  agreeableness: "       .",
  conscientiousness: "     .",
  negativeEmotionality: "   , ,    .",
  openMindedness: "     ."
};

const PersonalityQuiz = () => {
  const [currentQuestion, setCurrentQuestion] = useState(0);
  const [answers, setAnswers] = useState({});
  const [showResults, setShowResults] = useState(false);

  const handleAnswer = (value) => {
    setAnswers({
      ...answers,
      [currentQuestion]: value
    });
  };

  const calculateResults = () => {
    const scores = {
      extraversion: [],
      agreeableness: [],
      conscientiousness: [],
      negativeEmotionality: [],
      openMindedness: []
    };

    questions.forEach((question, index) => {
      if (answers[index] !== undefined) {
        let score = parseInt(answers[index]);
        if (question.reverse) {
          score = 6 - score;
        }
        scores[question.domain].push(score);
      }
    });

    const results = Object.entries(scores).map(([domain, scores]) => {
      const average = scores.length > 0 
        ? (scores.reduce((a, b) => a + b, 0) / scores.length).toFixed(2)
        : 0;
      
      const domainNames = {
        extraversion: "",
        agreeableness: "",
        conscientiousness: "",
        negativeEmotionality: " ",
        openMindedness: ""
      };

      return {
        domain: domainNames[domain],
        score: parseFloat(average),
        description: domainDescriptions[domain]
      };
    });

    return results;
  };

  if (showResults) {
    const results = calculateResults();
    
    return (
      <div className="quiz-card">
        <div className="quiz-header">
          <h2>  </h2>
        </div>
        <div className="quiz-content">
          <div className="chart-container">
            <BarChart width={600} height={250} data={results}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="domain" />
              <YAxis domain={[0, 5]} />
              <Tooltip />
              <Bar dataKey="score" fill="#4f46e5" />
            </BarChart>
          </div>
          
          <div className="results-container">
            {results.map((result, index) => (
              <div key={index} className="result-item">
                <div className="result-header">
                  <h3>{result.domain}</h3>
                  <span>{result.score}/5</span>
                </div>
                <div className="progress-bar">
                  <div 
                    className="progress-fill" 
                    style={{ width: `${result.score * 20}%` }} 
                  />
                </div>
                <p>{result.description}</p>
              </div>
            ))}
          </div>

          <button 
            onClick={() => {
              setShowResults(false);
              setAnswers({});
              setCurrentQuestion(0);
            }}
            className="quiz-button"
          >
             
          </button>
        </div>
      </div>
    );
  }

  const progress = ((currentQuestion + 1) / questions.length) * 100;

  return (
    <div className="quiz-card">
      <div className="quiz-header">
        <h2> {currentQuestion + 1} / {questions.length}</h2>
        <div className="progress-bar">
          <div 
            className="progress-fill" 
            style={{ width: `${progress}%` }} 
          />
        </div>
      </div>
      <div className="quiz-content">
        <p className="question-text">{questions[currentQuestion].text}</p>
        <div className="radio-group">
          {[
            ["1", "  "],
            ["2", "  "],
            ["3", ""],
            ["4", " "],
            ["5", " "]
          ].map(([value, label]) => (
            <label key={value} className="radio-option">
              <input
                type="radio"
                name="answer"
                value={value}
                checked={answers[currentQuestion] === value}
                onChange={(e) => handleAnswer(e.target.value)}
              />
              <span>{label}</span>
            </label>
          ))}
        </div>
        
        <div className="button-group">
          <button 
            onClick={() => currentQuestion > 0 && setCurrentQuestion(currentQuestion - 1)}
            disabled={currentQuestion === 0}
            className="quiz-button secondary"
          >
            
          </button>
          <button 
            onClick={() => {
              if (currentQuestion < questions.length - 1) {
                setCurrentQuestion(currentQuestion + 1);
              } else {
                setShowResults(true);
              }
            }}
            disabled={!answers[currentQuestion]}
            className="quiz-button primary"
          >
            {currentQuestion < questions.length - 1 ? '' : ' '}
          </button>
        </div>
      </div>
    </div>
  );
};

export default PersonalityQuiz;